interface IShape { double Area(); }
static double TotalArea(IShape[] shapes) => shapes.Sum(s => s.Area());
class Circle : IShape { public double Radius; public double Area() => Math.PI * Radius * Radius; }
class Square : IShape { public double Side; public double Area() => Side * Side; }
var shapes = new IShape[] { new Circle { Radius = 1 }, new Square { Side = 2 } };
Console.WriteLine(Math.Round(TotalArea(shapes), 2));

